import { formatDistanceToNow } from 'date-fns';
import { NewsItem, CategoryKey } from '../types';
import { getCategoryConfig } from '../lib/api';
import { ExternalLink } from 'lucide-react';

interface NewsRowProps {
  item: NewsItem;
}

export default function NewsRow({ item }: NewsRowProps) {
  const config = getCategoryConfig(item.category as Exclude<CategoryKey, 'all'>);
  const color = config?.color || { bg: 'bg-zinc-500/15', text: 'text-zinc-400', border: 'border-zinc-500/30' };

  let timeAgo = '';
  try {
    timeAgo = formatDistanceToNow(item.pubDate, { addSuffix: true });
    timeAgo = timeAgo
      .replace('about ', '~')
      .replace(' minutes', 'm')
      .replace(' minute', 'm')
      .replace(' hours', 'h')
      .replace(' hour', 'h')
      .replace(' days', 'd')
      .replace(' day', 'd')
      .replace('less than a m ago', 'just now');
  } catch {
    timeAgo = '';
  }

  return (
    <a
      href={item.link}
      target="_blank"
      rel="noopener noreferrer"
      className="block group"
    >
      <div className="flex items-start gap-2.5 px-3 py-2 hover:bg-zinc-800/60 transition-colors border-b border-zinc-800/50">
        {/* Category badge */}
        <div
          className={`shrink-0 mt-0.5 px-1.5 py-px text-[9px] font-bold tracking-wider uppercase border ${color.bg} ${color.text} ${color.border}`}
        >
          {config?.label || item.category}
        </div>

        {/* Content */}
        <div className="flex-1 min-w-0">
          <div className="flex items-start gap-1">
            <span className="text-zinc-200 text-xs leading-snug font-medium group-hover:text-white transition-colors line-clamp-2">
              {item.title}
            </span>
            <ExternalLink
              size={9}
              className="text-zinc-600 shrink-0 mt-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
            />
          </div>

          <div className="flex items-center gap-1.5 mt-0.5">
            <span className="text-[10px] text-zinc-500 truncate max-w-[120px]">
              {item.source}
            </span>
            {timeAgo && (
              <>
                <span className="text-zinc-700 text-[10px]">·</span>
                <span className="text-[10px] text-zinc-600 shrink-0">{timeAgo}</span>
              </>
            )}
          </div>
        </div>
      </div>
    </a>
  );
}

