            ))}
          </div>
        ) : (
          <ScrollArea className="h-full">
            {filtered.length > 0 ? (
              <div>
                {filtered.map((item) => (
                  <NewsRow key={item.id} item={item} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-zinc-500">
                <Newspaper size={18} className="mb-2 text-zinc-600" />
                <span className="text-[11px]">
                  {search
                    ? `No results for "${search}"`
                    : 'No news items found'}
                </span>
                {search && (
                  <button
                    onClick={() => setSearch('')}
                    className="mt-1.5 text-[10px] text-zinc-400 hover:text-zinc-200 underline"
                  >
                    Clear search
                  </button>
                )}
              </div>
            )}
          </ScrollArea>
        )}
      </div>

      {/* Footer */}
      <div className="flex-shrink-0 px-3 py-1 border-t border-zinc-800/60 flex items-center justify-between">
        <div className="flex items-center gap-1.5">
          {FEEDS.map((feed) => (
            <div
              key={feed.category}
              className={`w-1.5 h-1.5 ${
                feedResults[feed.category] === -1
                  ? 'bg-red-500'
                  : (feedResults[feed.category] || 0) > 0
                  ? feed.dotColor
                  : 'bg-zinc-700'
              }`}
              title={`${feed.label}: ${
                feedResults[feed.category] === -1
                  ? 'Failed'
                  : `${feedResults[feed.category] || 0} items`
              }`}
            />
          ))}
          <span className="text-[10px] text-zinc-600 ml-0.5">
            {activeFeedCount}/{FEEDS.length} feeds
          </span>
        </div>
        <span className="text-[10px] text-zinc-600">
          {filtered.length} headline{filtered.length !== 1 ? 's' : ''} • Auto-refresh 5m
        </span>
      </div>
    </div>
  );
}
